import { useState, useEffect } from 'react';
import { auth, db } from '../services/firebaseConfig'; // Apuntar al config unificado
import { onAuthStateChanged, User as FirebaseUser } from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';
import { User, UserRole } from '../types';

export const useAuthStatus = () => {
    const [user, setUser] = useState<User | null>(null);
    const [cargando, setCargando] = useState(true);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
            if (firebaseUser) {
                try {
                    // Intentar obtener el perfil completo de Firestore
                    const userRef = doc(db, "users", firebaseUser.uid);
                    const userSnap = await getDoc(userRef);

                    if (userSnap.exists()) {
                        // Usuario existe en DB: Usar sus datos reales (Rol, Organización, etc.)
                        setUser(userSnap.data() as User);
                    } else {
                        // Usuario no existe en DB (Primer login o error): Crear objeto temporal
                        // Nota: AuthService.loginWithGoogle en firebaseBackend debería manejar la creación
                        const tempUser: User = {
                            id: firebaseUser.uid,
                            email: firebaseUser.email || '',
                            name: firebaseUser.displayName || 'Usuario',
                            nickname: firebaseUser.email?.split('@')[0],
                            role: UserRole.ANALYST, // Rol por defecto temporal
                            avatar: firebaseUser.photoURL || '',
                            organization: 'Sin Asignar' 
                        };
                        setUser(tempUser);
                    }
                } catch (error) {
                    console.error("Error fetching user profile:", error);
                    setUser(null);
                }
            } else {
                setUser(null);
            }
            setCargando(false);
        });

        return () => unsubscribe(); 
    }, []);

    return { user, cargando };
};

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Login from './views/Login';
import Dashboard from './views/Dashboard';
import CreateDocument from './views/CreateDocument';
import DocumentDetail from './views/DocumentDetail';
import AdminUsers from './views/AdminUsers';
import AdminAssignments from './views/AdminAssignments';
import AdminDatabase from './views/AdminDatabase';
import Buffer from './views/Buffer';
import Profile from './views/Profile';
import { UserRole } from './types'; 
import { logoutUser } from './services/firebaseAuthService'; 
import { useAuthStatus } from './hooks/useAuthStatus'; 

const App: React.FC = () => {
    const { user, cargando } = useAuthStatus(); 

    const handleLogout = async () => {
        await logoutUser(); 
        // Forzar recarga o limpieza si es necesario, auth state listener se encargará del resto
    };

    if (cargando) {
        return <div className="flex h-screen items-center justify-center text-slate-500">Cargando aplicación...</div>;
    }

    return (
        <HashRouter>
            <Routes>
                <Route 
                    path="/login" 
                    element={!user ? <Login /> : <Navigate to="/" />} 
                />

                <Route
                    path="*"
                    element={
                        user ? (
                            <Layout user={user} onLogout={handleLogout}>
                                <Routes>
                                    <Route path="/" element={<Dashboard user={user} />} />

                                    <Route path="/inbox" element={<Buffer user={user} />} />
                                    <Route path="/new" element={<CreateDocument user={user} />} />
                                    <Route path="/doc/:id" element={<DocumentDetail user={user} />} />

                                    <Route path="/profile" element={<Profile user={user} onUpdate={() => window.location.reload()} />} /> 

                                    {/* Rutas de Administración */}
                                    <Route 
                                        path="/admin/users" 
                                        element={user.role === UserRole.ADMIN ? <AdminUsers /> : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/assignments" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? <AdminAssignments user={user} /> : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/database" 
                                        element={user.role === UserRole.ADMIN ? <AdminDatabase /> : <Navigate to="/" />} 
                                    />
                                    <Route path="*" element={<Navigate to="/" />} />
                                </Routes>
                            </Layout>
                        ) : (
                            <Navigate to="/login" />
                        )
                    }
                />
            </Routes>
        </HashRouter>
    );
};

export default App;

import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { DocumentService, HierarchyService, UserService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { Plus, FileText, Clock, CheckCircle, AlertTriangle, Filter, Trash2, Users, Search, X, Calendar, Inbox, ArrowRight, Activity, BookOpen, UserCheck, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface DashboardProps {
  user: User;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'REQUIRED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [docs, setDocs] = useState<Document[]>([]);
  const [requiredMap, setRequiredMap] = useState<Record<string, DocType[]>>({});
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  // Filter States
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState('');
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Quick Filter State (Stat Cards)
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'updatedAt',
    direction: 'desc' // Default: Newest first
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
        const [data, reqs, users] = await Promise.all([
            DocumentService.getAll(),
            HierarchyService.getRequiredTypesMap(),
            UserService.getAll()
        ]);
        setDocs(data);
        setRequiredMap(reqs);
        setAllUsers(users);
    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const handleDeleteDoc = async (id: string, e: React.MouseEvent) => {
    e.preventDefault(); // Prevent navigation
    if (!window.confirm('¿Eliminar este documento permanentemente?')) return;
    await DocumentService.delete(id);
    await loadData();
  };

  // Helper to determine if a doc is strictly required
  const isDocRequired = (doc: Document): boolean => {
      const key = `${doc.project}|${doc.microprocess}`;
      const requiredTypes = requiredMap[key];
      if (!requiredTypes) return false; 
      return doc.docType ? requiredTypes.includes(doc.docType) : false;
  };

  // Helper to get formatted assignees names (returns array of names for display filtering)
  const getAssigneesNames = (doc: Document): string[] => {
      if (!doc.assignees || doc.assignees.length === 0) return [doc.authorName]; 
      return doc.assignees
          .map(id => allUsers.find(u => u.id === id)?.name)
          .filter((name): name is string => !!name);
  };

  const handleQuickFilterClick = (type: QuickFilterType) => {
      if (quickFilter === type) {
          setQuickFilter('ALL'); // Toggle off
      } else {
          setQuickFilter(type);
          setFilterState(''); // Reset manual state dropdown to avoid conflicts
      }
  };

  const getFilteredDocs = () => {
    let filtered = docs;

    // 1. Role based base filtering
    if (user.role === UserRole.ANALYST) {
      filtered = docs.filter(d => 
        d.authorId === user.id || 
        (d.assignees && d.assignees.includes(user.id)) ||
        d.assignedTo === user.id
      );
    }

    // 2. Explicit Filters
    if (filterProject) {
        filtered = filtered.filter(d => d.project === filterProject);
    }
    if (filterMacro) {
        filtered = filtered.filter(d => d.macroprocess === filterMacro);
    }
    if (filterProcess) {
        filtered = filtered.filter(d => d.process === filterProcess);
    }
    if (filterDocType) {
        filtered = filtered.filter(d => d.docType === filterDocType);
    }
    if (filterState) {
        filtered = filtered.filter(d => d.state === filterState);
    }
    if (filterAnalyst) {
        filtered = filtered.filter(d => {
            const names = getAssigneesNames(d);
            // Check if ANY of the assignees matches the filter
            return names.includes(filterAnalyst);
        });
    }

    // 3. Quick Filters (Stat Cards)
    if (quickFilter !== 'ALL') {
        // All quick filters (except ALL) imply showing "Required" docs context
        filtered = filtered.filter(d => isDocRequired(d));

        switch (quickFilter) {
            case 'IN_PROCESS':
                filtered = filtered.filter(d => 
                    d.state === DocState.INITIATED || 
                    d.state === DocState.IN_PROCESS || 
                    d.state === DocState.INTERNAL_REVIEW
                );
                break;
            case 'REFERENT':
                filtered = filtered.filter(d => 
                    d.state === DocState.SENT_TO_REFERENT || 
                    d.state === DocState.REFERENT_REVIEW
                );
                break;
            case 'CONTROL':
                filtered = filtered.filter(d => 
                    d.state === DocState.SENT_TO_CONTROL || 
                    d.state === DocState.CONTROL_REVIEW
                );
                break;
            case 'FINISHED':
                filtered = filtered.filter(d => d.state === DocState.APPROVED);
                break;
            case 'REQUIRED':
                // Already filtered by isDocRequired above
                break;
        }
    }

    return filtered;
  };

  // Sorting Logic
  const handleSort = (key: SortKey) => {
      let direction: 'asc' | 'desc' = 'asc';
      if (sortConfig.key === key && sortConfig.direction === 'asc') {
          direction = 'desc';
      }
      setSortConfig({ key, direction });
  };

  const getSortedDocs = (filtered: Document[]) => {
      return [...filtered].sort((a, b) => {
          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt':
                  return (new Date(a.updatedAt).getTime() - new Date(b.updatedAt).getTime()) * modifier;
              case 'project':
                  return (a.project || '').localeCompare(b.project || '') * modifier;
              case 'microprocess':
                  const nameA = a.microprocess || a.title;
                  const nameB = b.microprocess || b.title;
                  return nameA.localeCompare(nameB) * modifier;
              case 'state':
                   return (a.progress - b.progress) * modifier;
              default:
                  return 0;
          }
      });
  };

  const filteredDocs = getFilteredDocs();
  const sortedDocs = getSortedDocs(filteredDocs);

  // Extract unique values for dropdowns
  const baseDocs = user.role === UserRole.ANALYST ? 
    docs.filter(d => d.authorId === user.id || (d.assignees && d.assignees.includes(user.id))) : 
    docs;

  const uniqueProjects = Array.from(new Set(baseDocs.map(d => d.project).filter(Boolean))) as string[];

  const uniqueMacros = Array.from(new Set(
      baseDocs.filter(d => !filterProject || d.project === filterProject)
      .map(d => d.macroprocess).filter(Boolean)
  )) as string[];

  const uniqueProcesses = Array.from(new Set(
      baseDocs.filter(d => (!filterProject || d.project === filterProject) && (!filterMacro || d.macroprocess === filterMacro))
      .map(d => d.process).filter(Boolean)
  )) as string[];

  const uniqueDocTypes = Array.from(new Set(
      baseDocs.filter(d => 
        (!filterProject || d.project === filterProject) && 
        (!filterMacro || d.macroprocess === filterMacro) &&
        (!filterProcess || d.process === filterProcess)
      )
      .map(d => d.docType).filter(Boolean)
  )) as string[];

  // Flattened list of individual analysts
  const uniqueAnalysts = Array.from(new Set(
      baseDocs.filter(d => 
        (!filterProject || d.project === filterProject) && 
        (!filterMacro || d.macroprocess === filterMacro)
      )
      .flatMap(d => getAssigneesNames(d))
  )).sort() as string[];

  // Calculate Stats based on BASE filtered documents (ignoring quick filter for the counts themselves to stay static relative to dropdowns)
  const contextDocs = (() => {
      let d = docs;
      if (user.role === UserRole.ANALYST) {
          d = docs.filter(doc => doc.authorId === user.id || (doc.assignees && doc.assignees.includes(user.id)));
      }
      if (filterProject) d = d.filter(doc => doc.project === filterProject);
      if (filterMacro) d = d.filter(doc => doc.macroprocess === filterMacro);
      if (filterProcess) d = d.filter(doc => doc.process === filterProcess);
      if (filterDocType) d = d.filter(doc => doc.docType === filterDocType);
      if (filterAnalyst) d = d.filter(doc => getAssigneesNames(doc).includes(filterAnalyst));
      return d.filter(doc => isDocRequired(doc));
  })();

  const stats = {
    totalRequired: contextDocs.length,
    inProcess: contextDocs.filter(d => 
        d.state === DocState.INITIATED || 
        d.state === DocState.IN_PROCESS || 
        d.state === DocState.INTERNAL_REVIEW
    ).length,
    referent: contextDocs.filter(d => 
        d.state === DocState.SENT_TO_REFERENT || 
        d.state === DocState.REFERENT_REVIEW
    ).length,
    control: contextDocs.filter(d => 
        d.state === DocState.SENT_TO_CONTROL || 
        d.state === DocState.CONTROL_REVIEW
    ).length,
    finished: contextDocs.filter(d => d.state === DocState.APPROVED).length
  };

  const chartData = [
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control Gestión', value: stats.control, color: '#f97316' },
    { name: 'Terminados', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const clearFilters = () => {
      setFilterProject('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterDocType('');
      setFilterState('');
      setFilterAnalyst('');
      setQuickFilter('ALL');
  };

  const hasFilters = filterProject || filterMacro || filterProcess || filterDocType || filterState || filterAnalyst || quickFilter !== 'ALL';

  const SortIcon = ({ column }: { column: SortKey }) => {
      if (sortConfig.key !== column) return <ArrowUpDown size={14} className="text-slate-300 opacity-0 group-hover:opacity-100 transition-opacity" />;
      return sortConfig.direction === 'asc' 
        ? <ArrowUp size={14} className="text-indigo-600" /> 
        : <ArrowDown size={14} className="text-indigo-600" />;
  };

  const showAnalystFilter = user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR;

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando dashboard...</div>;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-900">Dashboard</h1>
            <p className="text-slate-500">Vista general para {user.name} ({user.role})</p>
        </div>
        <div className="flex gap-2">
            {user.role === UserRole.ADMIN && (
                <Link to="/admin/users" className="inline-flex items-center justify-center px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors shadow-sm">
                    <Users size={18} className="mr-2" />
                    Gestionar Usuarios
                </Link>
            )}
            {user.role === UserRole.ANALYST && (
                <Link to="/new" className="inline-flex items-center justify-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm">
                    <Plus size={18} className="mr-2" />
                    Nueva Solicitud
                </Link>
            )}
        </div>
      </div>

      {/* Stats Cards - Interactive */}
      <div className="grid grid-cols-1 md:grid-cols-5 gap-3">
        <StatCard 
            title="Doc. Requeridos" 
            value={stats.totalRequired} 
            icon={BookOpen} 
            color="bg-slate-100 text-slate-600" 
            isActive={quickFilter === 'REQUIRED'}
            onClick={() => handleQuickFilterClick('REQUIRED')}
        />
        <StatCard 
            title="En Proceso" 
            value={stats.inProcess} 
            icon={Activity} 
            color="bg-blue-100 text-blue-600" 
            isActive={quickFilter === 'IN_PROCESS'}
            onClick={() => handleQuickFilterClick('IN_PROCESS')}
        />
        <StatCard 
            title="Referente" 
            value={stats.referent} 
            icon={Users} 
            color="bg-purple-100 text-purple-600" 
            isActive={quickFilter === 'REFERENT'}
            onClick={() => handleQuickFilterClick('REFERENT')}
        />
        <StatCard 
            title="Control Gestión" 
            value={stats.control} 
            icon={ShieldCheck} 
            color="bg-orange-100 text-orange-600" 
            isActive={quickFilter === 'CONTROL'}
            onClick={() => handleQuickFilterClick('CONTROL')}
        />
        <StatCard 
            title="Terminados" 
            value={stats.finished} 
            icon={CheckCircle} 
            color="bg-green-100 text-green-600" 
            isActive={quickFilter === 'FINISHED'}
            onClick={() => handleQuickFilterClick('FINISHED')}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Document List (Takes up 3 columns) */}
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">

            {/* Filter Bar */}
            <div className="p-4 border-b border-slate-100 bg-slate-50/50">
                <div className="flex items-center justify-between mb-3">
                    <h2 className="font-semibold text-slate-800 flex items-center gap-2">
                        <Filter size={18} className="text-indigo-600" />
                        Todos los Documentos
                    </h2>
                    {hasFilters && (
                        <button onClick={clearFilters} className="text-xs text-red-500 flex items-center gap-1 hover:underline">
                            <X size={14} /> Limpiar filtros
                        </button>
                    )}
                </div>

                {quickFilter !== 'ALL' && (
                    <div className="mb-3 px-3 py-2 bg-indigo-50 border border-indigo-100 rounded-lg text-sm text-indigo-700 flex items-center justify-between">
                        <span>
                            Filtrando por: <strong>
                                {quickFilter === 'REQUIRED' && 'Total Requeridos'}
                                {quickFilter === 'IN_PROCESS' && 'En Proceso'}
                                {quickFilter === 'REFERENT' && 'En Referente'}
                                {quickFilter === 'CONTROL' && 'Control de Gestión'}
                                {quickFilter === 'FINISHED' && 'Terminados'}
                            </strong>
                        </span>
                        <button onClick={() => setQuickFilter('ALL')} className="text-indigo-500 hover:text-indigo-800"><X size={16}/></button>
                    </div>
                )}

                <div className={`grid grid-cols-1 gap-3 ${showAnalystFilter ? 'md:grid-cols-6' : 'md:grid-cols-5'}`}>
                    <select 
                        value={filterProject} 
                        onChange={(e) => setFilterProject(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Proyecto (Todos)</option>
                        {uniqueProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>

                    {showAnalystFilter && (
                         <select 
                            value={filterAnalyst} 
                            onChange={(e) => setFilterAnalyst(e.target.value)}
                            className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        >
                            <option value="">Analista (Todos)</option>
                            {uniqueAnalysts.map(a => <option key={a} value={a}>{a}</option>)}
                        </select>
                    )}

                    <select 
                        value={filterMacro} 
                        onChange={(e) => setFilterMacro(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Macro (Todos)</option>
                        {uniqueMacros.map(m => <option key={m} value={m}>{m}</option>)}
                    </select>

                    <select 
                        value={filterProcess} 
                        onChange={(e) => setFilterProcess(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Proceso (Todos)</option>
                        {uniqueProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>

                    <select 
                        value={filterDocType} 
                        onChange={(e) => setFilterDocType(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Doc (Todos)</option>
                        {uniqueDocTypes.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>

                    <select 
                        value={filterState} 
                        onChange={(e) => {
                            setFilterState(e.target.value);
                            setQuickFilter('ALL'); // Disable quick filter if manual state is selected
                        }}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        disabled={quickFilter !== 'ALL' && quickFilter !== 'REQUIRED'}
                    >
                        <option value="">Estado (Todos)</option>
                        {Object.keys(STATE_CONFIG).map(key => (
                            <option key={key} value={key}>{STATE_CONFIG[key as DocState].label.split('(')[0]}</option>
                        ))}
                    </select>
                </div>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                        <tr>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('project')}
                            >
                                <div className="flex items-center gap-1">
                                    PROYECTO <SortIcon column="project" />
                                </div>
                            </th>
                            <th className="px-4 py-3">Jerarquía (Macro / Proceso)</th>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('microprocess')}
                            >
                                <div className="flex items-center gap-1">
                                    MICROPROCESO <SortIcon column="microprocess" />
                                </div>
                            </th>
                            <th className="px-4 py-3">Documento</th>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('state')}
                            >
                                <div className="flex items-center gap-1">
                                    Estado Actual <SortIcon column="state" />
                                </div>
                            </th>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('updatedAt')}
                            >
                                <div className="flex items-center gap-1">
                                    Última Actividad <SortIcon column="updatedAt" />
                                </div>
                            </th>
                            {user.role === UserRole.ADMIN && <th className="px-4 py-3 text-right">Admin</th>}
                        </tr>
                    </thead>
                    <tbody>
                        {sortedDocs.length === 0 ? (
                            <tr><td colSpan={7} className="p-8 text-center text-slate-400">No se encontraron documentos con los filtros aplicados.</td></tr>
                        ) : (
                            sortedDocs.map(doc => {
                                const isRequired = isDocRequired(doc);
                                const rowClass = isRequired 
                                    ? "border-b border-slate-50 hover:bg-slate-50 transition-colors" 
                                    : "border-b border-slate-50 bg-slate-100/50 text-slate-400 hover:bg-slate-100 transition-colors";

                                return (
                                    <tr key={doc.id} className={rowClass}>
                                        <td className="px-4 py-3 font-bold">
                                            {doc.project}
                                        </td>
                                        <td className="px-4 py-3 text-xs">
                                            <div className="font-medium">{doc.macroprocess}</div>
                                            <div>{doc.process}</div>
                                        </td>
                                        <td className="px-4 py-3 font-medium">
                                            {doc.microprocess || doc.title}
                                            {!isRequired && <div className="text-[10px] text-slate-400 font-normal mt-0.5">(No Requerido)</div>}

                                            {/* VISUALIZACIÓN VERTICAL DE ANALISTAS */}
                                            {showAnalystFilter && doc.assignees && doc.assignees.length > 0 && (
                                                <div className="flex flex-col gap-1 mt-1">
                                                    {doc.assignees.map(aid => {
                                                        const u = allUsers.find(user => user.id === aid);
                                                        return u ? (
                                                            <div key={aid} className="flex items-center gap-1 text-[10px] text-indigo-600">
                                                                <Users size={10} /> {u.name}
                                                            </div>
                                                        ) : null;
                                                    })}
                                                </div>
                                            )}
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex flex-col items-start gap-1">
                                                {doc.docType && (
                                                    <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded border ${
                                                        isRequired 
                                                        ? 'bg-indigo-50 text-indigo-700 border-indigo-100' 
                                                        : 'bg-slate-200 text-slate-500 border-slate-300'
                                                    }`}>
                                                        {doc.docType}
                                                    </span>
                                                )}
                                                <Link to={`/doc/${doc.id}`} className={`text-sm flex items-center hover:underline ${isRequired ? 'text-indigo-600 hover:text-indigo-800' : 'text-slate-500 hover:text-slate-700'}`}>
                                                    Ver Detalle <ArrowRight size={12} className="ml-1" />
                                                </Link>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex flex-col items-start gap-1">
                                                <span className={`px-2 py-1 rounded-full text-xs font-medium ${STATE_CONFIG[doc.state].color}`}>
                                                    {STATE_CONFIG[doc.state].label.split('(')[0]}
                                                </span>
                                                <span className="text-xs font-mono ml-1">
                                                    Ver: {doc.version} ({doc.progress}%)
                                                </span>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex items-center gap-1.5">
                                                <Calendar size={14} className={isRequired ? "text-slate-400" : "text-slate-300"} />
                                                <span>{new Date(doc.updatedAt).toLocaleDateString()}</span>
                                            </div>
                                            <div className="text-xs pl-5 opacity-70">
                                                {new Date(doc.updatedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                            </div>
                                        </td>
                                        {user.role === UserRole.ADMIN && (
                                            <td className="px-4 py-3 text-right">
                                                <button 
                                                    onClick={(e) => handleDeleteDoc(doc.id, e)}
                                                    className="text-slate-400 hover:text-red-600 transition-colors p-1"
                                                    title="Eliminar Documento"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </td>
                                        )}
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>
        </div>

        {/* Chart Column */}
        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 flex flex-col items-center justify-center min-h-[300px]">
                <h2 className="font-semibold text-slate-800 w-full mb-4 text-center">Distribución Requerida</h2>
                {chartData.length > 0 ? (
                    <div className="w-full h-64">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={chartData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={50}
                                    outerRadius={70}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    {chartData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={entry.color} />
                                    ))}
                                </Pie>
                                <Tooltip />
                                <Legend />
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : (
                    <p className="text-slate-400 text-center text-sm px-4">No hay datos requeridos para los filtros seleccionados.</p>
                )}
            </div>

            {/* Quick Summary Box */}
            <div className="bg-indigo-50 rounded-xl p-5 border border-indigo-100">
                <h3 className="font-bold text-indigo-900 mb-2">Resumen</h3>
                <p className="text-sm text-indigo-700 mb-4">
                    Visualizando {filteredDocs.length} documentos totales.
                </p>
                <ul className="text-sm space-y-2 text-indigo-800">
                    <li className="flex justify-between border-b border-indigo-200 pb-1">
                        <span>Total Requeridos:</span>
                        <span className="font-bold">{stats.totalRequired}</span>
                    </li>
                    <li className="flex justify-between border-b border-indigo-200 pb-1">
                        <span>Terminados:</span>
                        <span className="font-bold text-green-600">{stats.finished}</span>
                    </li>
                    <li className="flex justify-between text-xs pt-1 opacity-80">
                        <span>No Requeridos:</span>
                        <span>{filteredDocs.length - filteredDocs.filter(d => isDocRequired(d)).length}</span>
                    </li>
                </ul>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div 
        onClick={onClick}
        className={`bg-white p-3 rounded-xl shadow-sm border transition-all cursor-pointer flex items-center space-x-3 hover:shadow-md select-none
        ${isActive ? 'border-indigo-500 ring-2 ring-indigo-200 bg-indigo-50/20' : 'border-slate-200 hover:border-indigo-300'}`}
    >
        <div className={`p-2 rounded-lg ${color}`}>
            <Icon size={20} />
        </div>
        <div>
            <p className="text-slate-500 text-[10px] font-bold uppercase leading-tight">{title}</p>
            <p className={`text-xl font-bold leading-tight ${isActive ? 'text-indigo-700' : 'text-slate-900'}`}>{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, HierarchyService } from '../services/firebaseBackend';
import { User, DocState, DocType, UserHierarchy } from '../types';
import { parseDocumentFilename } from '../utils/filenameParser';
import { Save, ArrowLeft, Upload, FileCheck, FileX, AlertTriangle, Info, Layers, FileType, PlayCircle } from 'lucide-react';

interface Props {
  user: User;
}

type RequestType = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const CreateDocument: React.FC<Props> = ({ user }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(true);

  // Hierarchy Selection State with Strict Typing
  const [userHierarchy, setUserHierarchy] = useState<UserHierarchy>({});
  const [selectedProject, setSelectedProject] = useState<string>('');
  const [selectedMacro, setSelectedMacro] = useState<string>('');
  const [selectedProcess, setSelectedProcess] = useState<string>('');
  const [selectedMicro, setSelectedMicro] = useState<string>('');
  const [selectedDocType, setSelectedDocType] = useState<DocType | ''>('');
  const [requestType, setRequestType] = useState<RequestType | ''>('');

  // File Upload State
  const [file, setFile] = useState<File | undefined>(undefined);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');

  // Inferred Workflow State
  const [detectedState, setDetectedState] = useState<DocState>(DocState.INITIATED);
  const [detectedVersion, setDetectedVersion] = useState('0.0');
  const [detectedProgress, setDetectedProgress] = useState(10);

  useEffect(() => {
      loadHierarchy();
  }, []);

  const loadHierarchy = async () => {
      const hierarchy = await HierarchyService.getUserHierarchy(user.id);
      setUserHierarchy(hierarchy);
      setInitializing(false);
  };

  // Helper functions for safe extraction of hierarchy arrays
  // These explicitly return string[] to prevent implicit any errors in .map()
  const getProjects = (): string[] => {
      return Object.keys(userHierarchy);
  };

  const getMacros = (): string[] => {
      if (!selectedProject || !userHierarchy[selectedProject]) return [];
      return Object.keys(userHierarchy[selectedProject]);
  };

  const getProcesses = (): string[] => {
      if (!selectedProject || !selectedMacro || !userHierarchy[selectedProject]?.[selectedMacro]) return [];
      return Object.keys(userHierarchy[selectedProject][selectedMacro]);
  };

  const getMicros = (): string[] => {
      if (!selectedProject || !selectedMacro || !selectedProcess) return [];
      const processes = userHierarchy[selectedProject]?.[selectedMacro];
      if (!processes) return [];
      return processes[selectedProcess] || [];
  };

  // Reset downstream selections when upstream changes
  const handleProjectChange = (val: string) => {
      setSelectedProject(val);
      setSelectedMacro('');
      setSelectedProcess('');
      setSelectedMicro('');
      resetFile();
  };

  const handleMacroChange = (val: string) => {
      setSelectedMacro(val);
      setSelectedProcess('');
      setSelectedMicro('');
      resetFile();
  };

  const handleProcessChange = (val: string) => {
      setSelectedProcess(val);
      setSelectedMicro('');
      resetFile();
  };

  const handleMicroChange = (val: string) => {
      setSelectedMicro(val);
      resetFile();
  }

  const handleTypeChange = (val: string) => {
      setSelectedDocType(val as DocType);
      resetFile();
  }

  const handleRequestTypeChange = (val: string) => {
      setRequestType(val as RequestType);
      resetFile();
  }

  const resetFile = () => {
      setFile(undefined);
      setFileError([]);
      setIsFileValid(false);
      setTitle('');
      setDescription('');
      // Critical: Clear the input value so selecting the same file again triggers onChange
      if (fileInputRef.current) {
          fileInputRef.current.value = '';
      }
  };

  const mapParserStateToEnum = (parserState: string): DocState => {
      switch (parserState) {
          case 'Iniciado': return DocState.INITIATED;
          case 'En Proceso': return DocState.IN_PROCESS;
          case 'En revisión interna': return DocState.INTERNAL_REVIEW;
          case 'Enviado a Referente': return DocState.SENT_TO_REFERENT;
          case 'Revisión con referentes': return DocState.REFERENT_REVIEW;
          case 'Enviado a Control de Gestión': return DocState.SENT_TO_CONTROL;
          case 'Revisión con Control de Gestión': return DocState.CONTROL_REVIEW;
          case 'Aprobado': return DocState.APPROVED;
          default: return DocState.INITIATED;
      }
  };

  const getVersionHint = () => {
      if (requestType === 'INTERNAL') return '[v0.n] donde n es IMPAR';
      if (requestType === 'REFERENT') return '[v1.n.i] donde i es IMPAR';
      if (requestType === 'CONTROL') return '[v1.n.iAR] donde i es IMPAR';
      return '[Versión]';
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const selectedFile = e.target.files[0];
          setFile(selectedFile);

          // Validate with context AND request type!
          const result = parseDocumentFilename(
              selectedFile.name,
              selectedProject,
              selectedMicro,
              selectedDocType || undefined,
              requestType as RequestType || undefined
          );

          if (result.valido) {
              setIsFileValid(true);
              setFileError([]);

              // Only auto-fill title/description, rely on Selectors for hierarchy
              const cleanMicro = result.microproceso || selectedMicro;
              const cleanType = result.tipo || selectedDocType;
              setTitle(`${cleanMicro} - ${cleanType}`);
              setDescription(`Solicitud de ${requestType === 'INTERNAL' ? 'Revisión Interna' : requestType === 'REFERENT' ? 'Revisión Referente' : 'Control de Gestión'}`);

              if (result.estado) setDetectedState(mapParserStateToEnum(result.estado));
              if (result.nomenclatura) setDetectedVersion(result.nomenclatura);
              if (result.porcentaje) setDetectedProgress(result.porcentaje);

          } else {
              setIsFileValid(false);
              setFileError(result.errores);
              setTitle('');
              setDescription('');
          }
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !description || !file || !isFileValid || !selectedMicro || !selectedDocType) return;

    setLoading(true);
    try {
      const doc = await DocumentService.create(
          title, 
          description, 
          user,
          detectedState,
          detectedVersion,
          detectedProgress,
          file,
          {
              project: selectedProject,
              macro: selectedMacro,
              process: selectedProcess,
              micro: selectedMicro,
              docType: selectedDocType
          }
      );
      navigate(`/doc/${doc.id}`);
    } catch (error: any) {
      console.error(error);
      alert('Error al crear documento: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  if (initializing) return <div className="p-8 text-center text-slate-500">Cargando permisos...</div>;

  const projects = getProjects() as string[];
  const macros = getMacros() as string[];
  const processes = getProcesses() as string[];
  const micros = getMicros() as string[];
  const docTypes = ['AS IS', 'FCE', 'PM', 'TO BE'];

  return (
    <div className="max-w-4xl mx-auto pb-12">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 mb-6 text-sm">
            <ArrowLeft size={16} className="mr-1" />
            Volver
        </button>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 md:p-8">
            <div className="mb-8 border-b border-slate-100 pb-4">
                <h1 className="text-2xl font-bold text-slate-900 mb-2">Nueva Solicitud</h1>
                <p className="text-slate-500">
                   Completa la ficha técnica para iniciar una revisión formal.
                </p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">

                {/* Step 1: Hierarchy Selection */}
                <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
                    <h2 className="text-sm font-bold text-slate-800 uppercase tracking-wide mb-4 flex items-center gap-2">
                        <Layers size={18} className="text-indigo-600" />
                        1. Definición del Proceso
                    </h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {/* Project */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Proyecto</label>
                            <select 
                                value={selectedProject}
                                onChange={(e) => handleProjectChange(e.target.value)}
                                className="w-full p-2.5 border border-slate-300 rounded-lg bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                            >
                                <option value="">-- Seleccionar --</option>
                                {projects.map((p) => <option key={p} value={p}>{p}</option>)}
                            </select>
                        </div>

                        {/* Macroprocess */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Macroproceso</label>
                            <select 
                                value={selectedMacro}
                                onChange={(e) => handleMacroChange(e.target.value)}
                                disabled={!selectedProject}
                                className="w-full p-2.5 border border-slate-300 rounded-lg bg-white disabled:bg-slate-100 disabled:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none"
                            >
                                <option value="">-- Seleccionar --</option>
                                {macros.map((m) => <option key={m} value={m}>{m}</option>)}
                            </select>
                        </div>

                        {/* Process */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Proceso</label>
                            <select 
                                value={selectedProcess}
                                onChange={(e) => handleProcessChange(e.target.value)}
                                disabled={!selectedMacro}
                                className="w-full p-2.5 border border-slate-300 rounded-lg bg-white disabled:bg-slate-100 disabled:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none"
                            >
                                <option value="">-- Seleccionar --</option>
                                {processes.map((p) => <option key={p} value={p}>{p}</option>)}
                            </select>
                        </div>

                        {/* Microprocess */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Microproceso</label>
                            <select 
                                value={selectedMicro}
                                onChange={(e) => handleMicroChange(e.target.value)}
                                disabled={!selectedProcess}
                                className="w-full p-2.5 border border-slate-300 rounded-lg bg-white disabled:bg-slate-100 disabled:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none font-medium text-indigo-900"
                            >
                                <option value="">-- Seleccionar --</option>
                                {micros.map((m) => <option key={m} value={m}>{m}</option>)}
                            </select>
                        </div>

                        {/* Request Type Selector (New) */}
                        <div className="md:col-span-2">
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Tipo de Solicitud / Revisión</label>
                            <select 
                                value={requestType}
                                onChange={(e) => handleRequestTypeChange(e.target.value)}
                                disabled={!selectedMicro}
                                className="w-full p-2.5 border border-indigo-200 bg-indigo-50/50 text-indigo-900 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none font-medium"
                            >
                                <option value="">-- Seleccionar Tipo de Solicitud --</option>
                                <option value="INTERNAL">Revisión Interna (Inicio de Flujo)</option>
                                <option value="REFERENT">Revisión con Referente</option>
                                <option value="CONTROL">Control de Gestión</option>
                            </select>
                        </div>

                        {/* Report Type */}
                        <div className="md:col-span-2 mt-2 border-t border-slate-200 pt-4">
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Tipo de Informe</label>
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                                {docTypes.map(type => (
                                    <label key={type} className={`
                                        cursor-pointer border rounded-lg p-3 text-center transition-all
                                        ${selectedDocType === type 
                                            ? 'bg-indigo-600 text-white border-indigo-600 shadow-md transform scale-105' 
                                            : 'bg-white border-slate-300 text-slate-600 hover:border-indigo-400'}
                                    `}>
                                        <input 
                                            type="radio" 
                                            name="docType" 
                                            value={type} 
                                            checked={selectedDocType === type}
                                            onChange={(e) => handleTypeChange(e.target.value)}
                                            className="hidden"
                                            disabled={!requestType}
                                        />
                                        <span className="text-sm font-medium">{type}</span>
                                    </label>
                                ))}
                            </div>
                        </div>
                    </div>

                    {projects.length === 0 && (
                        <div className="mt-4 p-3 bg-yellow-50 text-yellow-700 text-sm rounded border border-yellow-200 flex items-center gap-2">
                            <AlertTriangle size={16} />
                            No tienes procesos asignados actualmente. Contacta al administrador.
                        </div>
                    )}
                </div>

                {/* Step 2: File Upload */}
                {selectedMicro && selectedDocType && requestType && (
                    <div className="animate-fadeIn">
                         <h2 className="text-sm font-bold text-slate-800 uppercase tracking-wide mb-4 flex items-center gap-2">
                            <Upload size={18} className="text-indigo-600" />
                            2. Carga de Archivo
                        </h2>

                        <div className="mb-4 p-3 bg-blue-50 text-blue-800 text-sm rounded border border-blue-100 flex items-start gap-2">
                            <Info size={18} className="mt-0.5 flex-shrink-0" />
                            <div>
                                <p className="font-semibold">Nomenclatura Requerida:</p>
                                <p className="font-mono mt-1 text-xs md:text-sm font-bold">
                                    {selectedProject} - {selectedMicro} - {selectedDocType.replace(' ', '')} - {getVersionHint()}
                                </p>
                            </div>
                        </div>

                        <div className={`border-2 border-dashed rounded-xl p-8 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : 
                              fileError.length > 0 ? 'border-red-300 bg-red-50' : 
                              'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>

                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleFileSelect}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />

                            {file ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={48} className="mx-auto mb-3" />
                                        <p className="font-semibold text-lg">{file.name}</p>
                                        <p className="text-sm mt-1">Validación exitosa</p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={48} className="mx-auto mb-3" />
                                        <p className="font-semibold text-lg">{file.name}</p>
                                        <div className="mt-3 text-sm text-left bg-white/50 p-3 rounded border border-red-200 inline-block">
                                            <ul className="list-disc pl-4 space-y-1">
                                                {fileError.map((err, idx) => (
                                                    <li key={idx}>{err}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={40} className="mx-auto mb-3" />
                                    <p className="font-medium">Click para seleccionar archivo</p>
                                    <p className="text-xs mt-2 text-slate-400">
                                        El nombre debe coincidir con la nomenclatura para {requestType}
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Step 3: Confirmation Form */}
                {isFileValid && selectedMicro && selectedDocType && (
                    <div className="animate-fadeIn border-t border-slate-100 pt-6">
                         <div className="flex items-center gap-3 bg-slate-50 p-4 rounded-lg border border-slate-200 mb-6">
                            <FileType size={20} className="text-slate-500 flex-shrink-0" />
                            <div className="text-sm text-slate-700 grid grid-cols-2 md:grid-cols-4 gap-4 w-full">
                                <div><span className="text-slate-400 text-xs uppercase block">Estado</span>{mapParserStateToEnum(parseDocumentFilename(file!.name).estado || '').replace(/_/g, ' ')}</div>
                                <div><span className="text-slate-400 text-xs uppercase block">Versión</span>{detectedVersion}</div>
                                <div><span className="text-slate-400 text-xs uppercase block">Progreso</span>{detectedProgress}%</div>
                                <div><span className="text-slate-400 text-xs uppercase block">Tipo</span>{selectedDocType}</div>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Título del Documento</label>
                                <input 
                                    type="text" 
                                    value={title}
                                    readOnly
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg bg-slate-100 text-slate-600 focus:outline-none cursor-not-allowed"
                                />
                            </div>
                             <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Descripción</label>
                                <input 
                                    type="text" 
                                    value={description}
                                    onChange={(e) => setDescription(e.target.value)}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                                    required
                                />
                            </div>
                        </div>

                        <div className="flex justify-end">
                            <button 
                                type="submit" 
                                disabled={loading}
                                className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 transition-colors shadow-md font-medium"
                            >
                                {loading ? 'Enviando...' : (
                                    <>
                                        <Save size={18} className="mr-2" />
                                        Crear Solicitud de Aprobación
                                    </>
                                )}
                            </button>
                        </div>
                    </div>
                )}
            </form>
        </div>
    </div>
  );
};

export default CreateDocument;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DocumentService, HistoryService, UserService } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, Upload, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, AlertTriangle, FileCheck, FileX, Info, ListFilter } from 'lucide-react';

interface Props {
  user: User;
}

type ApprovalContext = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [approvalType, setApprovalType] = useState<ApprovalContext | ''>(''); // New selector state
  const [responseFile, setResponseFile] = useState<File | undefined>(undefined);
  const [responseFileError, setResponseFileError] = useState<string | null>(null);
  const modalFileRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (id) loadData(id);
  }, [id]);

  const loadData = async (docId: string) => {
    setLoading(true);
    const [d, h, allUsers] = await Promise.all([
      DocumentService.getById(docId),
      HistoryService.getHistory(docId),
      UserService.getAll()
    ]);
    setDoc(d);
    setHistory(h);

    const coordinator = allUsers.find(u => u.role === UserRole.COORDINATOR);
    if (coordinator) setCoordinatorEmail(coordinator.email);

    if (d) {
        const author = allUsers.find(u => u.id === d.authorId);
        if (author) setAuthorEmail(author.email);
    }

    if (d && d.assignees && d.assignees.length > 0) {
        const names = d.assignees
            .map(aid => allUsers.find(u => u.id === aid)?.name)
            .filter(n => n) as string[];
        setAssigneeNames(names);
    }
    setLoading(false);
  };

  // Standard File Upload (Just adding attachments)
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || !e.target.files[0] || !doc) return;
    const file = e.target.files[0];
    const analisis = parseDocumentFilename(file.name, doc.project, doc.microprocess, doc.docType);

    if (!analisis.valido) {
      alert(`Error en nomenclatura:\n${analisis.errores.join('\n')}`);
      e.target.value = '';
      return;
    }

    if (!window.confirm(`Subir archivo: ${analisis.nomenclatura || 'Desconocida'}?`)) {
        e.target.value = '';
        return;
    }

    try {
      await DocumentService.uploadFile(doc.id, file, user);
      await loadData(doc.id);
    } catch (err: any) { alert(err.message); }
    finally { e.target.value = ''; }
  };

  // Trigger Action Flow
  const handleActionClick = (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'REQUEST_APPROVAL' | 'COMMENT') => {
      if (!doc) return;

      if (action === 'COMMENT') {
          if (!comment.trim()) {
              alert('Por favor escribe una observación antes de guardar.');
              return;
          }
          executeTransition('COMMENT', null, null);
          return;
      }

      if (action === 'REQUEST_APPROVAL') {
          if (!window.confirm('¿Solicitar aprobación para la versión actual?')) return;
          executeTransition('REQUEST_APPROVAL', null, null);
          return;
      }

      if (action === 'ADVANCE') {
          executeTransition('ADVANCE', null, null);
          return;
      }

      // For APPROVE or REJECT, Open Modal
      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) {
              alert('Por favor agrega un comentario/observación antes de rechazar.');
              return;
          }
          setPendingAction(action);
          setResponseFile(undefined);
          setResponseFileError(null);

          // Auto-detect approval type if based on current state (Legacy behavior fallback)
          let autoType: ApprovalContext | '' = '';
          if (doc.state === DocState.INTERNAL_REVIEW) autoType = 'INTERNAL';
          else if (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.REFERENT_REVIEW) autoType = 'REFERENT';
          else if (doc.state === DocState.SENT_TO_CONTROL || doc.state === DocState.CONTROL_REVIEW) autoType = 'CONTROL';

          setApprovalType(autoType);
          setShowResponseModal(true);
      }
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const file = e.target.files[0];
          setResponseFile(file);

          // 1. Basic Structure Validation
          const analisis = parseDocumentFilename(file.name, doc.project, doc.microprocess, doc.docType);
          if (!analisis.valido) {
              setResponseFileError(`Nomenclatura inválida: ${analisis.errores[0]}`);
              return;
          }

          // Determine Mock State for Validation based on Dropdown
          let mockStateForValidation = doc.state;
          if (approvalType === 'INTERNAL') mockStateForValidation = DocState.INTERNAL_REVIEW;
          else if (approvalType === 'REFERENT') mockStateForValidation = DocState.SENT_TO_REFERENT;
          else if (approvalType === 'CONTROL') mockStateForValidation = DocState.SENT_TO_CONTROL;

          // 2. Strict Coordinator Rule Validation
          const ruleCheck = validateCoordinatorRules(file.name, doc.version, mockStateForValidation, pendingAction);
          if (!ruleCheck.valid) {
              setResponseFileError(ruleCheck.error || 'Error de validación');
              return;
          }

          setResponseFileError(null);
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || responseFileError) return;
      if (pendingAction === 'APPROVE' && !approvalType) {
          alert('Debe seleccionar un Tipo de Aprobación.');
          return;
      }

      // Extract Clean Version
      const parts = responseFile.name.replace(/\.[^/.]+$/, "").split(' - ');
      const newVersion = parts[parts.length - 1];

      if (window.confirm(`Confirma ${pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR'} con archivo ${newVersion}?`)) {
          setShowResponseModal(false);
          await executeTransition(pendingAction, responseFile, newVersion);
      }
  };

  const executeTransition = async (action: any, file: File | null, customVersion: string | null) => {
      if (!doc) return;
      setActionLoading(true);
      try {
        await DocumentService.transitionState(
            doc.id, user, action, 
            comment || (action === 'REQUEST_APPROVAL' ? 'Solicitud de Aprobación Enviada' : 'Cambio de estado'),
            file || undefined,
            customVersion || undefined
        );
        setComment('');
        await loadData(doc.id);
      } catch (err: any) {
        alert('Error: ' + err.message);
      } finally {
        setActionLoading(false);
      }
  };

  const handleGmailNotification = () => {
    if (!doc || !coordinatorEmail) return;
    const subject = encodeURIComponent(`Solicitud de Aprobación SGD: ${doc.project} - ${doc.microprocess}`);
    const body = encodeURIComponent(`Estimado Coordinador,\n\nSolicitud de revisión para ${doc.title}.\nVersión: ${doc.version}\n\nAtentamente,\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyAnalyst = () => {
      if (!doc || !authorEmail) return;
      const subject = encodeURIComponent(`Respuesta Solicitud SGD: ${doc.project} - ${doc.microprocess}`);
      const body = encodeURIComponent(`Estimado/a ${doc.authorName},\n\nRevisión completada.\nEstado: ${STATE_CONFIG[doc.state].label}\nObservaciones: ${comment}\n\nAtentamente,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${authorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // Helper to get hint based on selector
  const getCurrentHint = () => {
      let mockState = doc?.state || DocState.INITIATED;
      if (approvalType === 'INTERNAL') mockState = DocState.INTERNAL_REVIEW;
      else if (approvalType === 'REFERENT') mockState = DocState.SENT_TO_REFERENT;
      else if (approvalType === 'CONTROL') mockState = DocState.SENT_TO_CONTROL;

      return getCoordinatorRuleHint(mockState, pendingAction || 'APPROVE');
  };

  if (loading || !doc) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const hasWriteAccess = (user.role === UserRole.ANALYST && (isAssignee || isAuthor)) || user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canUpload = user.role === UserRole.ANALYST && (isAssignee || isAuthor) && (doc.state === DocState.INITIATED || doc.state === DocState.IN_PROCESS || doc.state === DocState.REJECTED);
  const canRequestApproval = user.role === UserRole.ANALYST && (isAssignee || isAuthor) && !doc.hasPendingRequest && (doc.state === DocState.IN_PROCESS || doc.state === DocState.INTERNAL_REVIEW || doc.state === DocState.SENT_TO_REFERENT);
  const canRestart = user.role === UserRole.ANALYST && (isAssignee || isAuthor) && doc.state === DocState.REJECTED;

  // LOGIC UPDATE: Allow Coordinator/Admin to approve proactively OR if request is pending
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const isDocActive = doc.state !== DocState.APPROVED;

  // MODIFICATION: Allow Analysts (Author/Assignee) to also use the Approve button to trigger validation modal
  const canApprove = (isCoordinatorOrAdmin || (user.role === UserRole.ANALYST && (isAssignee || isAuthor))) && isDocActive;

  const canReject = canApprove;
  const canNotifyCoordinator = user.role === UserRole.ANALYST && coordinatorEmail && doc.state !== DocState.APPROVED;
  const canNotifyAuthor = isCoordinatorOrAdmin && authorEmail && doc.authorId !== user.id;

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <button onClick={() => navigate('/')} className="flex items-center text-slate-500 hover:text-slate-800 text-sm">
        <ArrowLeft size={16} className="mr-1" /> Volver al Dashboard
      </button>

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}>
                <Activity size={16} className="mr-2" />
                {config.label}
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div><p className="text-slate-500">Analistas</p>{assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>)}</div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${doc.progress}%` }}></div></div><span className="font-medium">{doc.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">
            {/* Archivos Adjuntos */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                <h3 className="font-semibold text-slate-800 mb-4 flex items-center"><Paperclip size={18} className="mr-2 text-indigo-500" /> Archivos Adjuntos</h3>
                <ul className="space-y-2 mb-4">
                    {doc.files.map(file => (
                        <li key={file.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg text-sm border border-slate-100">
                            <div className="flex items-center overflow-hidden">
                                <FileText size={16} className="text-slate-400 mr-3 flex-shrink-0" />
                                <span className="truncate font-medium text-slate-700">{file.name}</span>
                            </div>
                        </li>
                    ))}
                    {doc.files.length === 0 && <p className="text-sm text-slate-400 italic">No hay archivos.</p>}
                </ul>
                {canUpload && (
                    <label className="block p-4 border-2 border-dashed border-indigo-200 rounded-xl hover:bg-indigo-50 transition-colors cursor-pointer text-center text-indigo-600">
                        <input type="file" onChange={handleFileUpload} className="hidden" />
                        <Upload size={24} className="mx-auto mb-2" />
                        <span className="text-sm font-medium">Subir nueva versión</span>
                    </label>
                )}
            </div>

            {/* Acciones */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                 <h3 className="font-semibold text-slate-800 mb-4">Acciones de Flujo</h3>
                 <textarea 
                    className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500"
                    rows={3}
                    placeholder="Escriba aquí sus observaciones o comentarios..."
                    value={comment}
                    onChange={(e) => setComment(e.target.value)}
                 />
                 <div className="flex flex-wrap gap-3">
                    {hasWriteAccess && <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>}
                    {canNotifyCoordinator && <button onClick={handleGmailNotification} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm"><Mail size={16} className="mr-2" /> Notificar Coord.</button>}
                    {canNotifyAuthor && <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm"><Mail size={16} className="mr-2" /> Notificar Analista</button>}
                    {canRequestApproval && <button onClick={() => handleActionClick('REQUEST_APPROVAL')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><Send size={16} className="mr-2" /> Solicitar Aprobación</button>}
                    {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}
                    {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                    {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                 </div>
            </div>
        </div>

        {/* Historial (Right Column) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-fit max-h-[600px] overflow-y-auto">
            <h3 className="font-semibold text-slate-800 mb-4 border-b border-slate-100 pb-2">Historial</h3>
            <div className="space-y-6 pl-4 border-l-2 border-slate-100 relative">
                {history.map(h => (
                    <div key={h.id} className="relative">
                        <div className={`absolute -left-[21px] top-1 h-3 w-3 rounded-full border-2 border-white ${h.action === 'Observación' ? 'bg-indigo-400' : 'bg-slate-300'}`}></div>
                        <div className="text-xs text-slate-400 mb-0.5">{new Date(h.timestamp).toLocaleString()}</div>
                        <p className="text-sm font-medium text-slate-800">{h.action} <span className="font-normal text-slate-500">por {h.userName}</span></p>
                        {h.comment && <div className="mt-1 p-2 bg-slate-50 rounded text-xs text-slate-600 italic border border-slate-100">"{h.comment}"</div>}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* MODAL DE RESPUESTA (APROBAR/RECHAZAR) */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>
                          {pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}
                          {pendingAction === 'APPROVE' ? 'Aprobar Documento' : 'Rechazar Documento'}
                      </h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>

                  <div className="p-6 space-y-4">
                        {/* SELECTOR DE CONTEXTO (NUEVO) */}
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1 flex items-center gap-1">
                                <ListFilter size={14} /> Tipo de Aprobación / Contexto
                            </label>
                            <select 
                                value={approvalType} 
                                onChange={(e) => {
                                    setApprovalType(e.target.value as ApprovalContext);
                                    setResponseFile(undefined); // Reset file to force re-validation
                                    setResponseFileError(null);
                                }}
                                className="w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                            >
                                <option value="">-- Seleccionar Etapa --</option>
                                <option value="INTERNAL">Aprobación Revisión Interna (v1.0)</option>
                                <option value="REFERENT">Aprobación Referente (v1.n / v1.nAR)</option>
                                <option value="CONTROL">Aprobación Control Gestión (v1.nAR / v1.nACG)</option>
                            </select>
                        </div>

                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex items-start gap-3">
                            <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                            <div>
                                <p className="text-xs font-bold text-blue-800 uppercase mb-1">Nomenclatura Requerida</p>
                                <p className="text-sm font-mono font-bold text-blue-900">
                                    {approvalType ? getCurrentHint() : 'Seleccione un tipo de aprobación'}
                                </p>
                            </div>
                        </div>

                        <div className={`border-2 border-dashed rounded-xl p-6 flex flex-col items-center justify-center text-center transition-colors
                            ${!approvalType ? 'bg-slate-50 border-slate-200 cursor-not-allowed opacity-60' : 
                               responseFileError ? 'border-red-300 bg-red-50' : 
                               responseFile ? 'border-green-300 bg-green-50' : 
                               'border-slate-300 hover:bg-slate-50 hover:border-indigo-300 cursor-pointer'}`}>

                            <input 
                                type="file" 
                                ref={modalFileRef}
                                className="hidden"
                                disabled={!approvalType}
                                onChange={handleResponseFileSelect}
                            />

                            {responseFile ? (
                                <div>
                                    {responseFileError ? (
                                        <>
                                            <FileX size={32} className="text-red-500 mx-auto mb-2" />
                                            <p className="font-bold text-red-700">{responseFile.name}</p>
                                            <p className="text-xs text-red-600 mt-1">{responseFileError}</p>
                                            <button onClick={() => modalFileRef.current?.click()} className="text-xs underline text-red-800 mt-2">Cambiar archivo</button>
                                        </>
                                    ) : (
                                        <>
                                            <FileCheck size={32} className="text-green-500 mx-auto mb-2" />
                                            <p className="font-bold text-green-700">{responseFile.name}</p>
                                            <p className="text-xs text-green-600 mt-1">Archivo válido</p>
                                            <button onClick={() => modalFileRef.current?.click()} className="text-xs underline text-green-800 mt-2">Cambiar archivo</button>
                                        </>
                                    )}
                                </div>
                            ) : (
                                <div onClick={() => approvalType && modalFileRef.current?.click()} className={approvalType ? "cursor-pointer" : ""}>
                                    <Upload size={32} className="text-slate-400 mx-auto mb-2" />
                                    <p className="text-sm font-medium text-slate-600">
                                        {approvalType ? 'Click para subir archivo' : 'Seleccione un Tipo primero'}
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button>
                            <button 
                                onClick={handleSubmitResponse}
                                disabled={!responseFile || !!responseFileError || !approvalType}
                                className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all
                                    ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}
                                    disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useState, useEffect } from 'react';
import { UserService } from '../services/firebaseBackend';
import { User, UserRole } from '../types';
import { Trash2, UserPlus, Shield, Briefcase, User as UserIcon, X, Lock, Pencil } from 'lucide-react';

const AdminUsers: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nickname, setNickname] = useState('');
  const [role, setRole] = useState<UserRole>(UserRole.ANALYST);
  const [organization, setOrganization] = useState('');
  const [password, setPassword] = useState('');

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    setLoading(true);
    const data = await UserService.getAll();
    setUsers(data);
    setLoading(false);
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm('¿Estás seguro de que quieres eliminar este usuario?')) return;
    try {
        await UserService.delete(id);
        await loadUsers();
    } catch (error) {
        console.error(error);
    }
  };

  const handleEdit = (user: User) => {
      setEditingUserId(user.id);
      setName(user.name);
      setEmail(user.email);
      setNickname(user.nickname || '');
      setRole(user.role);
      setOrganization(user.organization);
      setPassword(''); // Don't show current password
      setShowForm(true);
  };

  const handleCreateNew = () => {
      setEditingUserId(null);
      resetForm();
      setShowForm(true);
  };

  const handleCancel = () => {
      setShowForm(false);
      resetForm();
      setEditingUserId(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !email || !organization) return;

    // Auto-append domain if missing for ease of use (only if not editing or if user typed it out)
    let finalEmail = email;
    if (!finalEmail.includes('@') && !email.includes('.')) {
        finalEmail += '@empresa.com';
    }

    try {
        if (editingUserId) {
            // Update
            const updatePayload: Partial<User> = {
                name,
                email: finalEmail,
                nickname: nickname || undefined,
                role,
                organization,
            };
            if (password) {
                updatePayload.password = password;
            }
            await UserService.update(editingUserId, updatePayload);
        } else {
            // Create
            if (!password) {
                alert('La contraseña es obligatoria para nuevos usuarios.');
                return;
            }
            await UserService.create({
                name,
                email: finalEmail,
                nickname: nickname || undefined,
                role,
                organization,
                password
            } as User); // Adjusted typing for creation
        }

        setShowForm(false);
        resetForm();
        setEditingUserId(null);
        await loadUsers();
    } catch (err: any) {
        alert(err.message);
    }
  };

  const resetForm = () => {
      setName('');
      setEmail('');
      setNickname('');
      setOrganization('');
      setRole(UserRole.ANALYST);
      setPassword('');
  };

  return (
    <div className="space-y-6">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
                <h1 className="text-2xl font-bold text-slate-900">Gestión de Usuarios</h1>
                <p className="text-slate-500">Administra perfiles y permisos del sistema.</p>
            </div>
            <button 
                onClick={showForm ? handleCancel : handleCreateNew}
                className={`inline-flex items-center px-4 py-2 text-white rounded-lg transition-colors shadow-sm ${showForm ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'}`}
            >
                {showForm ? <X size={18} className="mr-2" /> : <UserPlus size={18} className="mr-2" />}
                {showForm ? 'Cancelar' : 'Nuevo Usuario'}
            </button>
        </div>

        {/* Create/Edit User Form */}
        {showForm && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 animate-fadeIn">
                <h2 className="font-semibold text-slate-800 mb-4">{editingUserId ? 'Editar Usuario' : 'Registrar Nuevo Usuario'}</h2>
                <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Nombre Completo</label>
                        <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                        <input type="text" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required placeholder="usuario@empresa.com" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Usuario Corto / Nickname</label>
                        <div className="relative">
                            <input 
                                type="text" 
                                value={nickname} 
                                onChange={(e) => setNickname(e.target.value)} 
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" 
                                placeholder="Ej: jsmith"
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">
                            Contraseña
                            {editingUserId && <span className="text-slate-400 font-normal ml-2">(Dejar en blanco para no cambiar)</span>}
                        </label>
                        <div className="relative">
                            <input 
                                type="text" 
                                value={password} 
                                onChange={(e) => setPassword(e.target.value)} 
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" 
                                placeholder={editingUserId ? "••••••••" : "Establecer contraseña"}
                                required={!editingUserId}
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Organización / Área</label>
                        <input type="text" value={organization} onChange={(e) => setOrganization(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Rol</label>
                        <select value={role} onChange={(e) => setRole(e.target.value as UserRole)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500">
                            <option value={UserRole.ANALYST}>Analista</option>
                            <option value={UserRole.COORDINATOR}>Coordinador</option>
                            <option value={UserRole.ADMIN}>Administrador</option>
                        </select>
                    </div>
                    <div className="md:col-span-2 flex justify-end mt-2">
                        <button type="submit" className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition-colors">
                            {editingUserId ? 'Guardar Cambios' : 'Crear Usuario'}
                        </button>
                    </div>
                </form>
            </div>
        )}

        {/* Users List */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                        <tr>
                            <th className="px-6 py-3">Usuario</th>
                            <th className="px-6 py-3">Nickname</th>
                            <th className="px-6 py-3">Rol</th>
                            <th className="px-6 py-3">Organización</th>
                            <th className="px-6 py-3 text-right">Acciones</th>
                        </tr>
                    </thead>
                    <tbody>
                        {users.map(u => (
                            <tr key={u.id} className="border-b border-slate-50 hover:bg-slate-50 transition-colors">
                                <td className="px-6 py-4 flex items-center gap-3">
                                    <img src={u.avatar} alt={u.name} className="w-8 h-8 rounded-full bg-slate-200" />
                                    <div>
                                        <p className="font-medium text-slate-900">{u.name}</p>
                                        <p className="text-xs text-slate-500">{u.email}</p>
                                    </div>
                                </td>
                                <td className="px-6 py-4 font-mono text-slate-600">
                                    {u.nickname || '-'}
                                </td>
                                <td className="px-6 py-4">
                                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium 
                                        ${u.role === UserRole.ADMIN ? 'bg-purple-100 text-purple-800' : 
                                          u.role === UserRole.COORDINATOR ? 'bg-blue-100 text-blue-800' : 
                                          'bg-green-100 text-green-800'}`}>
                                        {u.role}
                                    </span>
                                </td>
                                <td className="px-6 py-4 text-slate-600">{u.organization}</td>
                                <td className="px-6 py-4 text-right">
                                    <div className="flex justify-end gap-2">
                                        <button 
                                            onClick={() => handleEdit(u)}
                                            className="text-slate-400 hover:text-indigo-600 p-1 hover:bg-indigo-50 rounded transition-colors"
                                            title="Editar usuario"
                                        >
                                            <Pencil size={18} />
                                        </button>
                                        <button 
                                            onClick={() => handleDelete(u.id)}
                                            className="text-slate-400 hover:text-red-600 p-1 hover:bg-red-50 rounded transition-colors"
                                            title="Eliminar usuario"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        {users.length === 0 && !loading && (
                            <tr><td colSpan={5} className="px-6 py-8 text-center text-slate-400">No hay usuarios registrados.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );
};

export default AdminUsers;

import React, { useState, useEffect } from 'react';
import { HierarchyService, UserService } from '../services/firebaseBackend';
import { User, UserRole, FullHierarchy, ProcessNode, DocType } from '../types';
import { 
  FolderTree, Search, ChevronRight, ChevronDown, Plus, X, Edit, Trash2, FileText, CheckSquare, Square, Save, Layers, Filter
} from 'lucide-react';

interface Props {
  user: User; // Admin User
}

const AdminAssignments: React.FC<Props> = ({ user }) => {
  const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  // Filters State
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterMicro, setFilterMicro] = useState(''); // Text Search
  const [filterAnalyst, setFilterAnalyst] = useState('');

  const [expandedProjects, setExpandedProjects] = useState<Record<string, boolean>>({ 'HPC': true, 'HSR': true });

  // Edit Assignment Modal State
  const [showEditModal, setShowEditModal] = useState(false);
  const [modalProject, setModalProject] = useState('');
  const [modalMacro, setModalMacro] = useState('');
  const [modalProcess, setModalProcess] = useState('');
  const [modalMicro, setModalMicro] = useState('');
  const [currentAssignees, setCurrentAssignees] = useState<string[]>([]);
  const [matrixKeyToUpdate, setMatrixKeyToUpdate] = useState<string | null>(null);

  // Create Microprocess Modal State
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [newProject, setNewProject] = useState('');
  const [newMacro, setNewMacro] = useState('');
  const [newProcess, setNewProcess] = useState('');
  const [newMicroName, setNewMicroName] = useState('');
  const [newAssignees, setNewAssignees] = useState<string[]>([]);
  const [newRequiredTypes, setNewRequiredTypes] = useState<DocType[]>(['AS IS', 'FCE', 'PM', 'TO BE']); // Default all checked

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const [h, u] = await Promise.all([
      HierarchyService.getFullHierarchy(),
      UserService.getAll()
    ]);
    setHierarchy(h);
    setAllUsers(u.filter(usr => usr.role === UserRole.ANALYST));
    setLoading(false);
  };

  const toggleProject = (proj: string) => {
    setExpandedProjects(prev => ({ ...prev, [proj]: !prev[proj] }));
  };

  const handleDelete = async (project: string, micro: string) => {
      if(!window.confirm(`¿Estás seguro de que deseas eliminar el microproceso "${micro}" de la matriz?\nEsta acción es irreversible en esta vista.`)) return;
      try {
          await HierarchyService.deleteMicroprocess(project, micro);
          await loadData();
      } catch (e: any) {
          alert(e.message);
      }
  };

  // --- Handlers for EDIT Modal ---
  const handleEditAssignment = (
      proj: string, macro: string, proc: string, microObj: ProcessNode
  ) => {
      setModalProject(proj);
      setModalMacro(macro);
      setModalProcess(proc);
      setModalMicro(microObj.name);
      setMatrixKeyToUpdate(microObj.docId);
      setCurrentAssignees([...microObj.assignees]); // Copy
      setShowEditModal(true);
  };

  const handleAddAssignee = (userId: string) => {
      if (!userId) return;
      if (!currentAssignees.includes(userId)) {
          setCurrentAssignees([...currentAssignees, userId]);
      }
  };

  const handleRemoveAssignee = (userId: string) => {
      setCurrentAssignees(currentAssignees.filter(id => id !== userId));
  };

  const handleSubmitAssignment = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!matrixKeyToUpdate) return;

      try {
          await HierarchyService.updateMatrixAssignment(matrixKeyToUpdate, currentAssignees, user.id);
          setShowEditModal(false);
          await loadData();
      } catch (err: any) {
          alert(err.message);
      }
  };

  const handleToggleRequiredType = async (matrixKey: string, type: DocType) => {
      await HierarchyService.toggleRequiredType(matrixKey, type);
      await loadData();
  };

  // --- Handlers for CREATE Modal ---
  const resetCreateForm = () => {
      setNewProject('');
      setNewMacro('');
      setNewProcess('');
      setNewMicroName('');
      setNewAssignees([]);
      setNewRequiredTypes(['AS IS', 'FCE', 'PM', 'TO BE']);
  };

  const handleOpenCreateModal = () => {
      resetCreateForm();
      setShowCreateModal(true);
  };

  const handleAddNewAssignee = (userId: string) => {
      if (!userId || newAssignees.includes(userId)) return;
      setNewAssignees([...newAssignees, userId]);
  };

  const handleRemoveNewAssignee = (userId: string) => {
      setNewAssignees(newAssignees.filter(id => id !== userId));
  };

  const handleToggleNewType = (type: DocType) => {
      if (newRequiredTypes.includes(type)) {
          setNewRequiredTypes(newRequiredTypes.filter(t => t !== type));
      } else {
          setNewRequiredTypes([...newRequiredTypes, type]);
      }
  };

  const handleSubmitCreate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newProject || !newMacro || !newProcess || !newMicroName) {
          alert('Todos los campos de jerarquía y nombre son obligatorios.');
          return;
      }
      try {
          await HierarchyService.addMicroprocess(
              newProject, newMacro, newProcess, newMicroName, newAssignees, newRequiredTypes
          );
          setShowCreateModal(false);
          resetCreateForm();
          await loadData();
          // Ensure the project is expanded to show the new node
          setExpandedProjects(prev => ({ ...prev, [newProject]: true }));
      } catch (err: any) {
          alert(err.message);
      }
  };

  // Helper getters for Create Modal Cascading
  const getCreateMacros = () => newProject && hierarchy[newProject] ? Object.keys(hierarchy[newProject]) : [];
  const getCreateProcesses = () => newProject && newMacro && hierarchy[newProject]?.[newMacro] ? Object.keys(hierarchy[newProject][newMacro]) : [];

  // --- Filters Helpers ---
  const getAvailableMacros = () => {
      const macros = new Set<string>();
      Object.keys(hierarchy).forEach(proj => {
          if (filterProject && proj !== filterProject) return;
          Object.keys(hierarchy[proj]).forEach(m => macros.add(m));
      });
      return Array.from(macros).sort();
  };

  const getAvailableProcesses = () => {
      const processes = new Set<string>();
      Object.keys(hierarchy).forEach(proj => {
          if (filterProject && proj !== filterProject) return;
          Object.keys(hierarchy[proj]).forEach(m => {
              if (filterMacro && m !== filterMacro) return;
              Object.keys(hierarchy[proj][m]).forEach(p => processes.add(p));
          });
      });
      return Array.from(processes).sort();
  };

  const clearFilters = () => {
      setFilterProject('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterMicro('');
      setFilterAnalyst('');
  };

  // Flattened Data for Table View within Project
  const getFlattenedRows = (project: string) => {
      const rows: any[] = [];
      const macros = hierarchy[project] || {};

      Object.keys(macros).forEach(macro => {
          if (filterMacro && macro !== filterMacro) return;

          Object.keys(macros[macro]).forEach(proc => {
              if (filterProcess && proc !== filterProcess) return;

              const nodes = macros[macro][proc];
              nodes.forEach(node => {
                  // Text Search for Microprocess
                  if (filterMicro && !node.name.toLowerCase().includes(filterMicro.toLowerCase())) return;

                  // Analyst Filter
                  if (filterAnalyst && !node.assignees.includes(filterAnalyst)) return;

                  rows.push({ macro, proc, node });
              });
          });
      });
      return rows;
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando matriz de procesos...</div>;

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterMicro || filterAnalyst;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Matriz de Asignaciones</h1>
          <p className="text-slate-500">Gestione los responsables y defina los documentos requeridos.</p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             <button 
                onClick={handleOpenCreateModal}
                className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm font-medium whitespace-nowrap"
            >
                <Plus size={18} className="mr-2" />
                Nuevo Microproceso
            </button>
        </div>
      </div>

      {/* FILTER BAR */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <div className="flex items-center justify-between mb-3 border-b border-slate-100 pb-2">
              <h3 className="font-semibold text-slate-700 flex items-center gap-2">
                  <Filter size={18} className="text-indigo-600" /> Filtros de Matriz
              </h3>
              {hasActiveFilters && (
                  <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1">
                      <X size={14} /> Limpiar Todo
                  </button>
              )}
          </div>
          <div className="grid grid-cols-1 md:grid-cols-5 gap-3">
              <select 
                  value={filterProject} 
                  onChange={(e) => setFilterProject(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Proyecto (Todos)</option>
                  {Object.keys(hierarchy).map(p => <option key={p} value={p}>{p}</option>)}
              </select>

              <select 
                  value={filterMacro} 
                  onChange={(e) => setFilterMacro(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Macroproceso (Todos)</option>
                  {getAvailableMacros().map(m => <option key={m} value={m}>{m}</option>)}
              </select>

              <select 
                  value={filterProcess} 
                  onChange={(e) => setFilterProcess(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Proceso (Todos)</option>
                  {getAvailableProcesses().map(p => <option key={p} value={p}>{p}</option>)}
              </select>

              <div className="relative">
                  <Search size={16} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                      type="text" 
                      placeholder="Buscar Microproceso..."
                      value={filterMicro}
                      onChange={(e) => setFilterMicro(e.target.value)}
                      className="w-full pl-8 p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
              </div>

               <select 
                  value={filterAnalyst} 
                  onChange={(e) => setFilterAnalyst(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Analista (Todos)</option>
                  {allUsers.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
              </select>
          </div>
      </div>

      <div className="space-y-4">
        {Object.keys(hierarchy).map(projectKey => {
            if (filterProject && projectKey !== filterProject) return null;

            const rows = getFlattenedRows(projectKey);
            if (rows.length === 0) return null;

            return (
                <div key={projectKey} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    {/* Project Header */}
                    <div 
                        onClick={() => toggleProject(projectKey)}
                        className="flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 cursor-pointer transition-colors border-b border-slate-200"
                    >
                        <div className="flex items-center gap-2 font-bold text-slate-800 text-lg">
                            {expandedProjects[projectKey] ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
                            <FolderTree size={20} className="text-indigo-600" />
                            Proyecto {projectKey}
                        </div>
                        <span className="text-xs text-slate-500 font-medium bg-white px-2 py-1 rounded border border-slate-200">
                            {rows.length} Microprocesos
                        </span>
                    </div>

                    {/* Table View */}
                    {expandedProjects[projectKey] && (
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-50/50">
                                    <tr>
                                        <th className="px-4 py-3 w-1/4">Jerarquía (Macro / Proceso)</th>
                                        <th className="px-4 py-3 w-1/4">Microproceso</th>
                                        <th className="px-4 py-3 w-1/5">Documentos Definidos</th>
                                        <th className="px-4 py-3 w-1/4">Analistas Responsables</th>
                                        <th className="px-4 py-3 text-right">Acciones</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {rows.map((row, idx) => (
                                        <tr key={`${row.node.docId}-${idx}`} className="hover:bg-slate-50 transition-colors">
                                            {/* Jerarquía */}
                                            <td className="px-4 py-3 align-top text-slate-600">
                                                <div className="font-semibold text-xs text-slate-700 mb-0.5">{row.macro}</div>
                                                <div className="text-xs text-slate-500 pl-2 border-l-2 border-slate-200">{row.proc}</div>
                                            </td>

                                            {/* Microproceso */}
                                            <td className="px-4 py-3 align-top">
