export const HierarchyService = {
    getFullHierarchy: async (): Promise<FullHierarchy> => {
        const q = query(collection(db, "custom_microprocesses"));
        const snapshot = await getDocs(q);
        const customNodes = snapshot.docs.map(d => d.data());

        const matrixDoc = await getDoc(doc(db, "config", "matrix_overrides"));
        const overrides = matrixDoc.exists() ? matrixDoc.data() : {};

        const typesDoc = await getDoc(doc(db, "config", "required_types"));
        const requiredTypesMap = typesDoc.exists() ? typesDoc.data() : {};

        const tree: FullHierarchy = {};

        INITIAL_DATA_LOAD.forEach(row => {
            if (!row || row.length < 5) return;
            const [project, macro, process, micro, namesStr] = row;
            const matrixKey = `${project}|${micro}`;

            let assigneeIds: string[] = [];
            if (overrides[matrixKey]) {
                assigneeIds = overrides[matrixKey];
            } else {
                 assigneeIds = []; 
            }

            if (!tree[project]) tree[project] = {};
            if (!tree[project][macro]) tree[project][macro] = {};
            if (!tree[project][macro][process]) tree[project][macro][process] = [];

            if (!tree[project][macro][process].find(m => m.name === micro)) {
                tree[project][macro][process].push({
                    name: micro,
                    docId: matrixKey,
                    assignees: assigneeIds,
                    requiredTypes: requiredTypesMap[matrixKey] || []
                });
            }
        });

        customNodes.forEach((node: any) => {
             const { project, macro, process, micro, assignees, requiredTypes } = node;
             const matrixKey = `${project}|${micro}`;

             const finalAssignees = overrides[matrixKey] || assignees || [];
             const finalTypes = requiredTypesMap[matrixKey] || requiredTypes || [];

             if (!tree[project]) tree[project] = {};
             if (!tree[project][macro]) tree[project][macro] = {};
             if (!tree[project][macro][process]) tree[project][macro][process] = [];

             if (!tree[project][macro][process].find(m => m.name === micro)) {
                 tree[project][macro][process].push({
                     name: micro,
                     docId: matrixKey,
                     assignees: finalAssignees,
                     requiredTypes: finalTypes
                 });
             }
        });

        return tree;
    },

    getUserHierarchy: async (userId: string): Promise<any> => {
        const full = await HierarchyService.getFullHierarchy();

        // Removed Super Analyst check logic completely

        const userTree: any = {};
        Object.keys(full).forEach(proj => {
            Object.keys(full[proj]).forEach(macro => {
                Object.keys(full[proj][macro]).forEach(proc => {
                    const nodes = full[proj][macro][proc];
                    nodes.forEach(node => {
                        // Strict check: Only assigned users can see the node
                        if (node.assignees.includes(userId)) {
                            if(!userTree[proj]) userTree[proj] = {};
                            if(!userTree[proj][macro]) userTree[proj][macro] = {};
                            if(!userTree[proj][macro][proc]) userTree[proj][macro][proc] = [];
                            userTree[proj][macro][proc].push(node.name);
                        }
                    })
                })
            })
        });
        return userTree;
    },

    getRequiredTypesMap: async () => {
        const docSnap = await getDoc(doc(db, "config", "required_types"));
        return docSnap.exists() ? docSnap.data() : {};
    },

    toggleRequiredType: async (matrixKey: string, type: DocType) => {
        const ref = doc(db, "config", "required_types");
        const snap = await getDoc(ref);
        const data = snap.exists() ? snap.data() : {};

        let types = data[matrixKey] || [];
        if (types.includes(type)) types = types.filter((t: string) => t !== type);
        else types.push(type);

        await setDoc(ref, { ...data, [matrixKey]: types });
    },

    updateMatrixAssignment: async (matrixKey: string, newAssignees: string[], updatedBy?: string) => {
        const ref = doc(db, "config", "matrix_overrides");
        const snap = await getDoc(ref);
        const data = snap.exists() ? snap.data() : {};

        await setDoc(ref, { ...data, [matrixKey]: newAssignees });

        const [proj, micro] = matrixKey.split('|');
        const q = query(collection(db, "documents"), where("project", "==", proj), where("microprocess", "==", micro));
        const docs = await getDocs(q);

        await Promise.all(docs.docs.map(async (d) => {
             await updateDoc(doc(db, "documents", d.id), {
                 assignees: newAssignees,
                 assignedTo: newAssignees[0]
             });
        }));
    },

    addMicroprocess: async (project: string, macro: string, process: string, microName: string, assignees: string[], requiredTypes: DocType[]) => {
        await addDoc(collection(db, "custom_microprocesses"), {
            project, macro, process, micro: microName, assignees, requiredTypes
        });

        const matrixKey = `${project}|${microName}`;
        await HierarchyService.updateMatrixAssignment(matrixKey, assignees);
        const ref = doc(db, "config", "required_types");
        const snap = await getDoc(ref);
        const data = snap.exists() ? snap.data() : {};
        await setDoc(ref, { ...data, [matrixKey]: requiredTypes });
    },

    deleteMicroprocess: async (project: string, microName: string) => {
        const q = query(collection(db, "custom_microprocesses"), where("project", "==", project), where("micro", "==", microName));
        const snapshot = await getDocs(q);
        await Promise.all(snapshot.docs.map(d => deleteDoc(d.ref)));

        const matrixKey = `${project}|${microName}`;

        const overridesRef = doc(db, "config", "matrix_overrides");
        const overridesSnap = await getDoc(overridesRef);
        if (overridesSnap.exists()) {
            const data = overridesSnap.data();
            if (data[matrixKey]) {
                const { [matrixKey]: _, ...rest } = data;
                await setDoc(overridesRef, rest);
            }
        }

        const typesRef = doc(db, "config", "required_types");
        const typesSnap = await getDoc(typesRef);
        if (typesSnap.exists()) {
            const data = typesSnap.data();
            if (data[matrixKey]) {
                const { [matrixKey]: _, ...rest } = data;
                await setDoc(typesRef, rest);
            }
        }
    }
};

export const DatabaseService = {
    importLegacyFromCSV: async (csvContent: string, onProgress?: (percent: number) => void) => {
        const lines = csvContent.split(/\r?\n/).filter(line => line.trim() !== '');
        if (lines.length < 2) throw new Error('CSV vacío');

        // Load current users to check for duplicates/linkages
        let users = await UserService.getAll();
        const currentUser = await AuthService.getCurrentUser();
        const adminId = currentUser?.id || 'admin';

        const parseLegacyDate = (d: string) => {
            if (!d || d.trim() === '') return new Date().toISOString();
            const parts = d.trim().split('-');
            if (parts.length === 3) return new Date(`${parts[2]}-${parts[1]}-${parts[0]}`).toISOString();
            return new Date().toISOString();
        };

        const parseLegacyState = (s: string): DocState => {
            if (!s) return DocState.INITIATED;
            const normalized = s.trim();
            if (normalized.startsWith('6')) return DocState.APPROVED;
            if (normalized.startsWith('5.1')) return DocState.CONTROL_REVIEW;
            if (normalized.startsWith('5')) return DocState.SENT_TO_CONTROL;
            if (normalized.startsWith('4.1')) return DocState.REFERENT_REVIEW;
            if (normalized.startsWith('4')) return DocState.SENT_TO_REFERENT;
            if (normalized.startsWith('3')) return DocState.INTERNAL_REVIEW;
            if (normalized.startsWith('2')) return DocState.IN_PROCESS;
            if (normalized.startsWith('1')) return DocState.INITIATED;
            return DocState.IN_PROCESS; 
        };

        const cleanPercentage = (p: string): number => {
            if (!p) return 0;
            return parseInt(p.replace('%', '').trim()) || 0;
        };

        const mapRole = (roleStr: string): UserRole => {
             const normalized = roleStr?.trim().toUpperCase();
             if (normalized === 'ADMIN') return UserRole.ADMIN;
             if (normalized === 'COORDINATOR' || normalized === 'COORDINADOR') return UserRole.COORDINATOR;
             return UserRole.ANALYST;
        };

        // === 1. DEEP CLEAN START ===

        // A. Clear 'documents'
        const qDocs = query(collection(db, "documents"));
        const snapDocs = await getDocs(qDocs);
        await Promise.all(snapDocs.docs.map(d => deleteDoc(d.ref)));

        // B. Clear 'custom_microprocesses' (Matrix)
        const qMicro = query(collection(db, "custom_microprocesses"));
        const snapMicro = await getDocs(qMicro);
        await Promise.all(snapMicro.docs.map(d => deleteDoc(d.ref)));

        // C. Clear 'history' (optional but cleaner)
        const qHist = query(collection(db, "history"));
        const snapHist = await getDocs(qHist);
        await Promise.all(snapHist.docs.map(d => deleteDoc(d.ref)));

        // D. Clear 'users' (EXCEPT the current admin to prevent lockout)
        const qUsers = query(collection(db, "users"));
        const snapUsers = await getDocs(qUsers);
        await Promise.all(snapUsers.docs.map(async (uDoc) => {
            const uData = uDoc.data();
            // Safety check: Don't delete self, don't delete 'admin' mock, don't delete explicit admins if needed
            if (uDoc.id !== adminId && uData.email !== 'admin@empresa.com' && uData.role !== 'ADMIN') {
                 await deleteDoc(uDoc.ref);
            }
        }));

        // Refresh users list after deletion to ensure we don't duplicate against deleted ones
        users = await UserService.getAll();
        // === 1. DEEP CLEAN END ===

        let imported = 0;
        const errors: string[] = [];
        const newMatrixOverrides: Record<string, string[]> = {};
        const newRequiredTypes: Record<string, DocType[]> = {}; 

        // Accumulator for unique hierarchy nodes
        const uniqueMicros = new Map<string, any>();

        const totalLines = lines.length - 1;

        // Skip Header (i=1)
        for (let i = 1; i < lines.length; i++) {

            // Progress Calculation
            if (onProgress) {
                onProgress(Math.round((i / totalLines) * 100));
            }

            const cols = lines[i].split(';');
            if (cols.length < 5) continue;

            // Updated Column Mapping based on new structure:
            // 0: ID, 1: PROJECT, 2: MACRO, 3: PROCESS, 4: MICRO
            // 5: Name, 6: Email, 7: Role
            const project = cols[1];
            const macro = cols[2];
            const process = cols[3];
            const micro = cols[4];

            const rawName = cols[5]?.trim();
            const rawEmail = cols[6]?.trim();
            const rawRole = cols[7]?.trim();

            // Resolve Assignee Logic
            let assignees: string[] = [adminId];
            let authorName = 'Admin (Migración)';

            // Strict Validation: Only create user if email looks like an email
            if (rawEmail && rawEmail.includes('@') && rawEmail.length > 3) {
                 // 1. Try to find existing user by Email
                 let foundUser = users.find(u => u.email.toLowerCase() === rawEmail.toLowerCase());

                 if (!foundUser) {
                     // 2. Create New User Profile in Firestore
                     // We use a sanitized email prefix or unique string for ID to ensure we can find it later
                     const generatedId = `user-${rawEmail.replace(/[^a-zA-Z0-9]/g, '')}`;

                     const newUser: User = {
                         id: generatedId,
                         name: rawName || rawEmail.split('@')[0],
                         email: rawEmail,
                         nickname: rawEmail.split('@')[0],
                         role: mapRole(rawRole),
                         organization: 'Procesos', // <-- CHANGED HERE
                         avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(rawName || 'U')}&background=random`,
                     };

                     try {
                        await setDoc(doc(db, "users", generatedId), newUser);
                        // Add to local cache to avoid duplicates in loop
                        users.push(newUser);
                        foundUser = newUser;
                     } catch (e) {
                         console.error("Error creating user from CSV:", e);
                         errors.push(`Error creando usuario ${rawEmail}: ${e}`);
                     }
                 }

                 if (foundUser) {
                     assignees = [foundUser.id];
                     authorName = foundUser.name;
                 }
            }

            if (project && micro) {
                const matrixKey = `${project}|${micro}`;
                newMatrixOverrides[matrixKey] = assignees;

                // Lookup Required Types from Matrix (Constants)
                const configRow = REQUIRED_DOCS_MATRIX.find(r => r[0] === project && r[1] === micro);
                let typesForMicro: DocType[] = [];

                if (configRow) {
                    if (configRow[2] === 1) typesForMicro.push('AS IS');
                    if (configRow[3] === 1) typesForMicro.push('FCE');
                    if (configRow[4] === 1) typesForMicro.push('PM');
                    if (configRow[5] === 1) typesForMicro.push('TO BE');
                } else {
                    // Fallback to all required if not defined in matrix
                    typesForMicro = ['AS IS', 'FCE', 'PM', 'TO BE'];
                }
                newRequiredTypes[matrixKey] = typesForMicro;

                // Store unique hierarchy node to populate 'custom_microprocesses' later
                if (!uniqueMicros.has(matrixKey)) {
                    uniqueMicros.set(matrixKey, {
                        project, macro, process, micro,
                        assignees,
                        requiredTypes: typesForMicro
                    });
                }
            }

            const baseDoc = {
                project, macroprocess: macro, process, microprocess: micro,
                authorId: assignees[0], authorName, assignedTo: assignees[0], assignees: assignees,
                files: []
            };

            const createLegacyDoc = async (type: DocType, progressStr: string, dateStr: string, versionStr: string, stateStr: string) => {
                if (versionStr && versionStr.trim() !== '') {
                     await addDoc(collection(db, "documents"), {
                         ...baseDoc,
                         title: `${project} - ${micro} - ${type}`,
                         description: `Migración: ${type} para ${micro}`,
                         docType: type,
                         progress: cleanPercentage(progressStr),
                         updatedAt: parseLegacyDate(dateStr),
                         createdAt: parseLegacyDate(dateStr),
                         version: versionStr.trim(),
                         state: parseLegacyState(stateStr),
                         hasPendingRequest: false
                     });
                     imported++;
                }
            }

            // New Indices for Document Columns
            // AS IS: 8, 9, 10, 11
            await createLegacyDoc('AS IS', cols[8], cols[9], cols[10], cols[11]);
            // FCE: 12, 13, 14, 15
            await createLegacyDoc('FCE', cols[12], cols[13], cols[14], cols[15]);
            // PM: 16, 17, 18, 19
            await createLegacyDoc('PM', cols[16], cols[17], cols[18], cols[19]);
            // TO BE: 20, 21, 22, 23
            await createLegacyDoc('TO BE', cols[20], cols[21], cols[22], cols[23]);
        }

        // 3. Populate 'custom_microprocesses' so Matrix View works
        const batchPromises: any[] = [];
        uniqueMicros.forEach((data) => {
            batchPromises.push(addDoc(collection(db, "custom_microprocesses"), data));
        });
        await Promise.all(batchPromises);

        await setDoc(doc(db, "config", "matrix_overrides"), newMatrixOverrides);
        await setDoc(doc(db, "config", "required_types"), newRequiredTypes);

        return { imported, errors };
    },
    exportData: async () => { return "Función no disponible en versión nube (contactar admin DB)"; },
    importData: async (jsonContent: string) => { 
        console.warn("Attempted JSON Restore on Cloud version.");
        throw new Error("La importación de respaldo JSON no está disponible en la versión Cloud. Utilice la importación CSV para migración inicial.");
    }
};

import { useState, useEffect } from 'react';
import { auth, db } from '../services/firebaseConfig';
import { onAuthStateChanged } from 'firebase/auth';
import { doc, getDoc, setDoc, deleteDoc, query, collection, where, getDocs, updateDoc } from 'firebase/firestore';
import { User, UserRole } from '../types';
import { UserService } from '../services/firebaseBackend';

export const useAuthStatus = () => {
    const [user, setUser] = useState<User | null>(null);
    const [cargando, setCargando] = useState(true);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
            if (firebaseUser) {
                try {
                    const userRef = doc(db, "users", firebaseUser.uid);
                    const userSnap = await getDoc(userRef);
                    const email = firebaseUser.email || '';

                    // Lista de correos que SIEMPRE deben ser Admin
                    const adminEmails = ['admin@empresa.com'];
                    const shouldBeAdmin = adminEmails.includes(email) || email.toLowerCase().startsWith('admin');

                    if (userSnap.exists()) {
                        // 1. El usuario ya tiene perfil
                        const userData = userSnap.data() as User;

                        // Auto-fix: Corregir roles según configuración dura (solo admins reales)
                        if (shouldBeAdmin && userData.role !== UserRole.ADMIN) {
                            console.log("Upgrading user to ADMIN.");
                            const updatedUser = { ...userData, role: UserRole.ADMIN, organization: 'Administración Sistema' };
                            await updateDoc(userRef, { role: UserRole.ADMIN, organization: 'Administración Sistema' });
                            setUser(updatedUser);
                        } else {
                            setUser(userData);
                        }
                    } else {
                        // 2. Nuevo Login o Migración
                        // Verificar si existe un perfil "Pre-cargado" (importado por CSV) con este email.
                        let existingProfile: User | null = null;
                        let oldDocRef = null;

                        if (email) {
                            const q = query(collection(db, "users"), where("email", "==", email));
                            const querySnapshot = await getDocs(q);
                            if (!querySnapshot.empty) {
                                // Encontramos un perfil huérfano (creado por CSV)
                                const docFound = querySnapshot.docs[0];
                                existingProfile = docFound.data() as User;
                                oldDocRef = docFound.ref;
                                console.log("Perfil pre-existente encontrado. Migrando a nuevo UID...");
                            }
                        }

                        if (existingProfile && oldDocRef) {
                            // MIGRACIÓN: Mover datos del ID antiguo al nuevo UID de Auth
                            const migratedUser: User = {
                                ...existingProfile,
                                id: firebaseUser.uid, // Actualizamos ID
                                avatar: firebaseUser.photoURL || existingProfile.avatar, // Preferir foto de Google si existe
                                role: shouldBeAdmin ? UserRole.ADMIN : existingProfile.role // Enforce admin check
                            };

                            // A. Crear nuevo usuario con ID de Google
                            await setDoc(userRef, migratedUser);

                            // B. Ejecutar migración profunda de referencias (Documentos, Matrices, Configs)
                            await UserService.migrateLegacyReferences(existingProfile.id, firebaseUser.uid);

                            // C. Eliminar documento antiguo para evitar duplicados
                            await deleteDoc(oldDocRef);

                            setUser(migratedUser);
                        } else {
                            // CREACIÓN NUEVA (Si no existía en CSV)
                            const newUser: User = {
                                id: firebaseUser.uid,
                                email: email,
                                name: firebaseUser.displayName || email.split('@')[0],
                                nickname: email.split('@')[0],
                                role: shouldBeAdmin ? UserRole.ADMIN : UserRole.ANALYST,
                                avatar: firebaseUser.photoURL || `https://ui-avatars.com/api/?name=${firebaseUser.displayName || email}`,
                                organization: shouldBeAdmin ? 'Administración Sistema' : 'Sin Asignar' 
                            };

                            await setDoc(userRef, newUser);
                            setUser(newUser);
                        }
                    }
                } catch (error) {
                    console.error("Error fetching/creating user profile:", error);
                    setUser(null);
                }
            } else {
                setUser(null);
            }
            setCargando(false);
        });

        return () => unsubscribe(); 
    }, []);

    return { user, cargando };
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, HierarchyService } from '../services/firebaseBackend';
import { User, DocState, DocType, UserHierarchy, UserRole } from '../types';
import { parseDocumentFilename } from '../utils/filenameParser';
import { Save, ArrowLeft, Upload, FileCheck, FileX, AlertTriangle, Info, Layers, FileType, PlayCircle } from 'lucide-react';

interface Props {
  user: User;
}

type RequestType = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const CreateDocument: React.FC<Props> = ({ user }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(true);

  // Hierarchy Selection State with Strict Typing
  const [userHierarchy, setUserHierarchy] = useState<UserHierarchy>({});
  const [selectedProject, setSelectedProject] = useState<string>('');
  const [selectedMacro, setSelectedMacro] = useState<string>('');
  const [selectedProcess, setSelectedProcess] = useState<string>('');
  const [selectedMicro, setSelectedMicro] = useState<string>('');
  const [selectedDocType, setSelectedDocType] = useState<DocType | ''>('');
  const [requestType, setRequestType] = useState<RequestType | ''>('');

  // File Upload State
  const [file, setFile] = useState<File | undefined>(undefined);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');

  // Inferred Workflow State
  const [detectedState, setDetectedState] = useState<DocState>(DocState.INITIATED);
  const [detectedVersion, setDetectedVersion] = useState('0.0');
  const [detectedProgress, setDetectedProgress] = useState(10);

  useEffect(() => {
      loadHierarchy();
  }, []);

  const loadHierarchy = async () => {
      // Si es Admin, cargamos la jerarquía completa transformada a formato simple
      if (user.role === UserRole.ADMIN) {
           const full = await HierarchyService.getFullHierarchy();
           const adminTree: UserHierarchy = {};

           // Convertir FullHierarchy (nodos complejos) a UserHierarchy (solo nombres)
           Object.keys(full).forEach(p => {
               adminTree[p] = {};
               Object.keys(full[p]).forEach(m => {
                   adminTree[p][m] = {};
                   Object.keys(full[p][m]).forEach(proc => {
                       adminTree[p][m][proc] = full[p][m][proc].map(n => n.name);
                   });
               });
           });
           setUserHierarchy(adminTree);
      } else {
          // Si es Analista, solo lo asignado
          const hierarchy = await HierarchyService.getUserHierarchy(user.id);
          setUserHierarchy(hierarchy);
      }
      setInitializing(false);
  };

  // Helper functions for safe extraction of hierarchy arrays
  // These explicitly return string[] to prevent implicit any errors in .map()
  const getProjects = (): string[] => {
      return Object.keys(userHierarchy);
  };

  const getMacros = (): string[] => {
      if (!selectedProject || !userHierarchy[selectedProject]) return [];
      return Object.keys(userHierarchy[selectedProject]);
  };

  const getProcesses = (): string[] => {
      if (!selectedProject || !selectedMacro || !userHierarchy[selectedProject]?.[selectedMacro]) return [];
      return Object.keys(userHierarchy[selectedProject][selectedMacro]);
  };

  const getMicros = (): string[] => {
      if (!selectedProject || !selectedMacro || !selectedProcess) return [];
      const processes = userHierarchy[selectedProject]?.[selectedMacro];
      if (!processes) return [];
      return processes[selectedProcess] || [];
  };

  // Reset downstream selections when upstream changes
  const handleProjectChange = (val: string) => {
      setSelectedProject(val);
      setSelectedMacro('');
      setSelectedProcess('');
      setSelectedMicro('');
      resetFile();
  };

  const handleMacroChange = (val: string) => {
      setSelectedMacro(val);
      setSelectedProcess('');
      setSelectedMicro('');
      resetFile();
  };

  const handleProcessChange = (val: string) => {
      setSelectedProcess(val);
      setSelectedMicro('');
      resetFile();
  };

  const handleMicroChange = (val: string) => {
      setSelectedMicro(val);
      resetFile();
  }

  const handleTypeChange = (val: string) => {
      setSelectedDocType(val as DocType);
      resetFile();
  }

  const handleRequestTypeChange = (val: string) => {
      setRequestType(val as RequestType);
      resetFile();
  }

  const resetFile = () => {
      setFile(undefined);
      setFileError([]);
      setIsFileValid(false);
      setTitle('');
      setDescription('');
      // Critical: Clear the input value so selecting the same file again triggers onChange
      if (fileInputRef.current) {
          fileInputRef.current.value = '';
      }
  };

  const mapParserStateToEnum = (parserState: string): DocState => {
      switch (parserState) {
          case 'Iniciado': return DocState.INITIATED;
          case 'En Proceso': return DocState.IN_PROCESS;
          case 'En revisión interna': return DocState.INTERNAL_REVIEW;
          case 'Enviado a Referente': return DocState.SENT_TO_REFERENT;
          case 'Revisión con referentes': return DocState.REFERENT_REVIEW;
          case 'Enviado a Control de Gestión': return DocState.SENT_TO_CONTROL;
          case 'Revisión con Control de Gestión': return DocState.CONTROL_REVIEW;
          case 'Aprobado': return DocState.APPROVED;
          default: return DocState.INITIATED;
      }
  };

  const getVersionHint = () => {
      if (requestType === 'INTERNAL') return '[v0.n] donde n es IMPAR';
      if (requestType === 'REFERENT') return '[v1.n.i] donde i es IMPAR';
      if (requestType === 'CONTROL') return '[v1.n.iAR] donde i es IMPAR';
      return '[Versión]';
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const selectedFile = e.target.files[0];
          setFile(selectedFile);

          // Validate with context AND request type!
          const result = parseDocumentFilename(
              selectedFile.name,
              selectedProject,
              selectedMicro,
              selectedDocType || undefined,
              requestType as RequestType || undefined
          );

          if (result.valido) {
              setIsFileValid(true);
              setFileError([]);

              // Only auto-fill title/description, rely on Selectors for hierarchy
              const cleanMicro = result.microproceso || selectedMicro;
              const cleanType = result.tipo || selectedDocType;
              setTitle(`${cleanMicro} - ${cleanType}`);
              setDescription(`Solicitud de ${requestType === 'INTERNAL' ? 'Revisión Interna' : requestType === 'REFERENT' ? 'Revisión Referente' : 'Control de Gestión'}`);

              if (result.estado) setDetectedState(mapParserStateToEnum(result.estado));
              if (result.nomenclatura) setDetectedVersion(result.nomenclatura);
              if (result.porcentaje) setDetectedProgress(result.porcentaje);

          } else {
              setIsFileValid(false);
              setFileError(result.errores);
              setTitle('');
              setDescription('');
          }
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !description || !file || !isFileValid || !selectedMicro || !selectedDocType) return;

    setLoading(true);

    // Create a promise that rejects after 15 seconds
    const timeoutPromise = new Promise((_, reject) => {
        setTimeout(() => reject(new Error("Tiempo de espera agotado. Verifique su conexión.")), 15000);
    });

    try {
      const createPromise = DocumentService.create(
          title, 
          description, 
          user,
          detectedState,
          detectedVersion,
          detectedProgress,
          file,
          {
              project: selectedProject,
              macro: selectedMacro,
              process: selectedProcess,
              micro: selectedMicro,
              docType: selectedDocType
          }
      );

      // Race between the creation logic and the timeout
      const doc = await Promise.race([createPromise, timeoutPromise]) as any;

      navigate(`/doc/${doc.id}`);
    } catch (error: any) {
      console.error(error);
      alert('Error al crear documento: ' + error.message);
    } finally {
      // Always reset loading state so the user can try again
      setLoading(false);
    }
  };

  if (initializing) return <div className="p-8 text-center text-slate-500">Cargando permisos...</div>;

  const projects = getProjects() as string[];
  const macros = getMacros() as string[];
  const processes = getProcesses() as string[];
  const micros = getMicros() as string[];
  const docTypes = ['AS IS', 'FCE', 'PM', 'TO BE'];

  return (
    <div className="max-w-4xl mx-auto pb-12">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 mb-6 text-sm">
            <ArrowLeft size={16} className="mr-1" />
            Volver
        </button>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 md:p-8">
            <div className="mb-8 border-b border-slate-100 pb-4">
                <h1 className="text-2xl font-bold text-slate-900 mb-2">Nueva Solicitud</h1>
                <p className="text-slate-500">
                   Completa la ficha técnica para iniciar una revisión formal.
                </p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">

                {/* Step 1: Hierarchy Selection */}
                <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
                    <h2 className="text-sm font-bold text-slate-800 uppercase tracking-wide mb-4 flex items-center gap-2">
                        <Layers size={18} className="text-indigo-600" />
                        1. Definición del Proceso
                    </h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {/* Project */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Proyecto</label>
                            <select 
                                value={selectedProject}
                                onChange={(e) => handleProjectChange(e.target.value)}
                                className="w-full p-2.5 border border-slate-300 rounded-lg bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                            >
