                                        </label>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="flex justify-end pt-6 gap-3 border-t border-slate-100 mt-6">
                        <button 
                            type="button" 
                            onClick={() => setShowCreateModal(false)}
